# Dictionary comprehension
numbers = [1, 2, 3, 4, 5]
squares_dict = {num: num * num for num in numbers}
even_squares = {num: num * num for num in numbers if num % 2 == 0}
print(f'Kvadrat lüğəti: {squares_dict}')
print(f'Cüt kvadratlar: {even_squares}')

// JavaScript kodu
const numbers = [1, 2, 3, 4, 5];
const squares = numbers.map(num => num * num);
console.log(squares);

